import API_BASE_URL from "../config/api";
import { buildHighlightsSearchUrl } from "./currentMatchweekHighlights";

const PATH = "v1/youtube/highlight";

function candidateUrls(home, away, date, homeScore, awayScore) {
  const qs = new URLSearchParams({
    home,
    away,
    date,
  });
  if (homeScore != null && awayScore != null) {
    qs.set("homeScore", String(homeScore));
    qs.set("awayScore", String(awayScore));
  }
  const pathWithQs = `${PATH}?${qs}`;
  const urls = [];
  const seen = new Set();
  const add = (u) => {
    if (u && !seen.has(u)) {
      seen.add(u);
      urls.push(u);
    }
  };
  add(`/api/${pathWithQs}`);
  if (API_BASE_URL) {
    add(`${API_BASE_URL}/api/${pathWithQs}`);
  }
  if (process.env.NODE_ENV === "production") {
    add(`/api/render-proxy?__path=${encodeURIComponent(pathWithQs)}`);
  }
  return urls;
}

/**
 * Direct `youtube.com/watch?v=…` when backend has YouTube Data API v3 configured; otherwise search URL.
 *
 * @param {{ homeTeam: string, awayTeam: string, date: string, homeScore: number, awayScore: number }} match
 * @returns {Promise<string>}
 */
export async function resolveYoutubeHighlightWatchUrl(match) {
  const fallback = buildHighlightsSearchUrl(match.homeTeam, match.awayTeam, match.date);
  const urls = candidateUrls(
    match.homeTeam,
    match.awayTeam,
    match.date,
    match.homeScore,
    match.awayScore
  );
  for (const url of urls) {
    try {
      const res = await fetch(url);
      if (!res.ok) continue;
      const data = await res.json();
      if (data?.url && typeof data.url === "string" && data.url.startsWith("http")) {
        return data.url;
      }
    } catch {
      /* try next candidate */
    }
  }
  return fallback;
}
